import{_ as e,o as a,c as t,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"烟气书页包","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/通用及综合类/司书战斗手册/体系书页/烟气/烟气书页包.md","filePath":"4.资源分区/6.技艺及称号/通用及综合类/司书战斗手册/体系书页/烟气/烟气书页包.md"}'),s={name:"4.资源分区/6.技艺及称号/通用及综合类/司书战斗手册/体系书页/烟气/烟气书页包.md"};function o(d,b,_,l,i,c){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"烟气书页包",tabindex:"-1"},[p("烟气书页包 "),r("a",{class:"header-anchor",href:"#烟气书页包","aria-label":'Permalink to "烟气书页包"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"灵魂蓝调012")])])],-1),n('<h1 id="烟气书页包-1" tabindex="-1">烟气书页包 <a class="header-anchor" href="#烟气书页包-1" aria-label="Permalink to &quot;烟气书页包&quot;">​</a></h1><p>烟气书页包</p><p>烟气：<br> 1.不具有【烟气缭绕】被动：每层烟气会使自身被攻击时，攻击者会额外获得其决心上的附加成功*1点环境加值。烟气不低于9层时，其还会获得1点攻击检定上的附加成功。烟气至多拥有10层，每一幕结束时烟气层数-1。同一资源所施加的烟气不会叠加计算。<br> 2.具有【烟气缭绕】被动：每层烟气会使自身攻击其他目标时，会额外获得其决心上的附加成功*1点环境加值。烟气不低于9层时，自身还会获得1点攻击检定上的附加成功。烟气至多拥有10层，每一幕结束时烟气层数-1。同一资源所施加的烟气不会叠加计算。</p><p>烟管技艺<br> 类型：应对技<br> 等级：D<br> 派系：无<br> 能耗：0点<br> 成分：动作<br> 动作：反射动作/标准动作<br> 射程：自身<br> 持续：1轮<br> 效果：<br> 在下一次的攻击中，必须以标准动作使用此书页的效果进行战斗，反射动作使用，并进行以下检定：<br> 格挡骰：若拼点成功，使自身获得2层烟气并恢复1点光芒，则获得决心上的附加成功*1点格挡防御<br> 闪避骰：若拼点成功，则获得决心上的附加成功*2点闪避防御</p><p>烟锤猛击<br> 类型：攻击技<br> 等级：D<br> 派系：无<br> 能耗：1点<br> 成分：动作<br> 动作：标准动作<br> 射程：接触范围<br> 持续：1轮<br> 效果：进行一次“决心+专注+专业（书页）”攻击检定，并进行以下拼点检定<br> 格挡骰：若拼点成功，则获得决心上的附加成功*1点格挡防御<br> 打击骰：若拼点成功，且成功造成伤害，则恢复1点光芒，并对目标施加3层烟气。</p><p>隐藏锋刃<br> 类型：攻击技<br> 等级：D<br> 派系：无<br> 能耗：1点<br> 成分：动作<br> 动作：标准动作<br> 射程：接触范围<br> 持续：1轮<br> 效果：<br> 使用时，消耗自身具有的2层烟气，并使接下来的这次攻击额外获得2点附加成功。<br> 进行一次“决心+专注+专业（书页）”攻击检定，并进行以下拼点检定<br> 闪避骰：若拼点成功，则获得决心上的附加成功*1点闪避防御。<br> 打击骰：若拼点成功，且成功造成伤害，则下一幕开始时使攻击目标获得2点不可豁免的流血点数。</p><p>烟锤袭击<br> 类型：攻击技<br> 等级：C<br> 派系：无<br> 能耗：1点<br> 成分：动作<br> 动作：标准动作<br> 射程：接触范围<br> 持续：1轮<br> 效果：<br> 使用时，若自身至少拥有9层烟气，则本次攻击额外获得决心上的附加成功*2点附加成功。<br> 进行一次“决心+专注+专业（书页）”攻击检定，并进行以下拼点检定：<br> 闪避骰：若拼点成功，则获得决心上的附加成功*1点闪避防御上的附加成功。<br> 斩击骰：若拼点成功，且成功造成伤害，则对目标施加2层烟气。</p><p>掩杀指示<br> 类型：攻击技<br> 等级：C<br> 派系：无<br> 能耗：2点<br> 成分：动作<br> 动作：标准动作<br> 射程：接触范围<br> 持续：1轮<br> 效果：<br> 进行一次“决心+专注+专业（书页）”攻击检定，并进行以下拼点检定：<br> 闪避骰：若拼点成功，则获得决心上的附加成功*1点闪避防御。若被攻击目标至少拥有2层烟气，则本次攻击额外获得决心上的附加成功*3点附加成功。<br> 穿刺骰：若拼点成功，则额外获得决心上的附加成功*1点攻击检定增强加值。<br> 斩击骰：若拼点成功，则额外获得决心上的附加成功*1点攻击检定增强加值。</p><p>官能丧失<br> 类型：攻击技<br> 等级：C<br> 派系：无<br> 能耗：3点<br> 成分：动作<br> 动作：标准动作<br> 射程：接触范围<br> 持续：1轮<br> 效果：<br> 进行一次“决心+专注+专业（书页）”攻击检定，并进行以下拼点检定：<br> 打击骰：若拼点成功，且成功造成伤害，则对目标施加7层烟气。<br> 闪避骰：若拼点成功，且成功造成伤害，则获得决心上的附加成功*1点闪避防御。</p><p>千刀万剐<br> 类型：攻击技<br> 等级：B<br> 派系：无<br> 能耗：2点<br> 成分：动作<br> 动作：标准动作<br> 射程：接触范围<br> 持续：1轮<br> 效果：<br> 进行一次“决心+专注+专业（书页）”攻击检定，并进行以下拼点检定：<br> 斩击骰：若拼点成功，且成功造成伤害，则下一幕开始时，使目标获得2点不可豁免的流血点数。消耗自身的2层烟气并使这次攻击获得决心上的附加成功*2点附加成功。<br> 斩击骰：若拼点成功，且成功造成伤害，则在下一幕开始时，目标每拥有2层烟气，就获得1点不可豁免的流血点数。</p><p>蒸汽喷发<br> 类型：攻击技<br> 等级：B<br> 派系：无<br> 能耗：3点<br> 成分：动作<br> 动作：标准动作<br> 射程：接触范围<br> 持续：1轮<br> 效果：<br> 进行一次“决心+专注+专业（书页）”攻击检定，并进行以下拼点检定：<br> 斩击骰：若拼点成功，则此次攻击获得决心上的附加成功*2点附加成功，并使自身获得4层烟气；且成功造成伤害时，使对方额外获得3层烟气。你可以再使用至多不超过标准动作的一张烟气书页，但是不能使用花费多于1点光芒的书页。</p><p>循迴永动<br> 类型：攻击技<br> 等级：B<br> 派系：无<br> 能耗：3点<br> 成分：动作<br> 动作：标准动作<br> 射程：接触范围<br> 持续：1轮<br> 效果：<br> 进行一次“决心+专注+专业（书页）”攻击检定，并进行以下拼点检定：<br> 斩击骰：若拼点成功，则使自身获得7层烟气；且成功造成伤害时，对目标施加4层烟气。<br> 斩击骰：若拼点成功，且成功造成伤害时，对目标施加4层烟气。<br> 格挡骰：若拼点成功，则获得决心上的附加成功*2点格挡防御上的附加成功。</p><p>浓烟喷射<br> 类型：攻击技<br> 等级：A<br> 限制：每场景一次<br> 派系：无<br> 能耗：4点<br> 成分：动作<br> 动作：标准动作<br> 射程：接触范围<br> 持续：1轮<br> 效果：<br> 进行一次“决心+专注+专业（书页）”攻击检定，并进行以下拼点检定：<br> 打击骰：若拼点成功，则使自身获得8层烟气；且成功造成伤害时，你每拥有1层烟气，就对被攻击目标施加1层烟气，最多不能超过上限，目标每拥有5层烟气，就在下一幕开始时对其施加决心上的附加成功*2点不可豁免的麻痹点数。<br> 格挡骰：若拼点成功，则获得决心上的附加成功*1点格挡防御上的附加成功。<br> 斩击骰：若拼点成功，则此次攻击获得决心上的附加成功*2点附加成功。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',15)])])}const m=e(s,[["render",o]]);export{f as __pageData,m as default};
